import logo from './logo.svg';
import './App.css';
import { useState } from 'react';
import { Block,Block_with_input } from './Block';

function f(t) { 
    const threshold = (24 / 116) * (24 / 116) * (24 / 116);
    if (t > threshold) {
        return Math.pow(t, 1 / 3);
    }
    else { 
        return 841 * t / 108 + 16 / 116;
    }
}
function xyz_to_lab(col_xyz) { 
    let col_lab = [0, 0, 0];
    col_lab[0]=116*f(col_xyz[1]/1.0)
}

function rgb_to_xyz(col_rgb) { 
    let col_xyz = [0, 0, 0];
    col_xyz[0] = 0.4124 * col_rgb[0] + 0.3576 * col_rgb[1] + 0.1805 * col_rgb[2];
    col_xyz[1] = 0.2126 * col_rgb[0] + 0.7152 * col_rgb[1] + 0.0722 * col_rgb[2];
    col_xyz[2] = 0.0193 * col_rgb[0] + 0.1192 * col_rgb[1] + 0.9505 * col_rgb[2];
    return col_xyz
}

function calc_distance(lab_1, lab_2) { 
    return Math.sqrt((xyz_1[0] - xyz_2[0]) * (xyz_1[0] - xyz_2[0]) + (xyz_1[1] - xyz_2[1]) * (xyz_1[1] - xyz_2[1]) + (xyz_1[2] - xyz_2[2]) * (xyz_1[2] - xyz_2[2]));
}

function to_linear(col_rgb) {
    let col_linear = [0, 0, 0];
    for (let i = 0; i < 3; i++) { 
        col_linear[i] = col_rgb[i];
        col_linear[i] /= 255;
        if (col_linear[i] < 0.04045) {
            col_linear[i] = col_linear[i] / 12.92;
        } else { 
            col_linear[i] = Math.pow((col_linear[i] + 0.055) / 1.055, 2.4);
        }
    }
    return col_linear;
}

function show_score(col_rgb_1, col_rgb_2) {
    let score=rgb_to_xyz(to_linear(col_rgb_1))
}

function App() {
    const [color_input, setColor_input] = useState({
        red: 0,
        green: 0,
        blue: 0,
    });
    const handleChange = (input) => e => {
        setColor_input({ ...color_input, [input]: e.target.value });
    };
    const col = {
        red: 200,
        blue: 0,
        green: 0,
    }
    let [is_visible, setIs_visible] = useState(true);


    return (
        <>
        <div className="App">
            <header className="App-header">
                <Block color_rgb={col} text="問題"></Block>
                <Block_with_input color_rgb={color_input} is_visible={is_visible} text="正解" handleChange={e => handleChange(e)}></Block_with_input>
                <button onClick={()=>setIs_visible(is_visible=false)}>aaa</button>
            </header>

        </div>

        </>
    );
}

export default App;
